content.text:
Enum təyin etmək üçün `enum` açar sözü istifadə olunur. Sintaksis belədir:
```c
enum name {
  member1,
  member2,
  // digər üzvlər
};
```
- **enum**: Enum təyin etdiyini göstərir.
- **name**: Enumun adı (məsələn, `Day`).
- **member1, member2**: Enumun üzvləri, hər biri bir sabitə uyğundur.
Enum təyin edildikdən sonra, onun üzvləri dəyişənlərə təyin oluna bilər:
```c
enum name variable;
```
Varsayılan olaraq, enum üzvlərinə 0-dan başlayaraq ardıcıl `int` dəyərləri təyin edilir, lakin istəyə uyğun dəyərlər də təyin etmək olar.

content.code:
#include <stdio.h>

enum Day {
  Monday,
  Tuesday,
  Wednesday,
  Thursday,
  Friday,
  Saturday,
  Sunday
};

int main() {
  enum Day today = Wednesday;
  printf("Today is day number: %d\n", today);
  return 0;
}
// Output:
// Today is day number: 2

#include <stdio.h>

enum Status {
  Inactive = 0,
  Active = 10,
  Suspended,
  Deleted = 20
};

int main() {
  enum Status user = Active;
  printf("User status: %d\n", user);
  user = Suspended;
  printf("User status after change: %d\n", user);
  return 0;
}
// Output:
// User status: 10
// User status after change: 11

#include <stdio.h>

enum Day {
  Monday,
  Tuesday,
  Wednesday,
  Thursday,
  Friday,
  Saturday,
  Sunday
};

void printDay(enum Day d) {
  switch (d) {
    case Monday:
      printf("Today is Monday\n");
      break;
    case Tuesday:
      printf("Today is Tuesday\n");
      break;
    case Wednesday:
      printf("Today is Wednesday\n");
      break;
    default:
      printf("Another day\n");
  }
}

int main() {
  enum Day today = Tuesday;
  printDay(today);
  return 0;
}
// Output:
// Today is Tuesday

#include <stdio.h>

enum Day {
  Monday,
  Tuesday,
  Wednesday
};

int main() {
  enum Day today = 10; // Səhv: Enum dəyərindən kənar rəqəm
  printf("Invalid day: %d\n", today);
  return 0;
}
// Output: (Gözlənilməz nəticə, çünki 10 enum dəyəri deyil)

